import React, { useState } from 'react';
import axios from 'axios';
import Swal from 'sweetalert2';
import { useNavigate } from 'react-router-dom';
import Navbar from './Navbar';

function Login()
{
    const navigate = useNavigate();
    const [loginInput, setLoginInput] = useState({
        email: '',
        password: '',
        error_list: {},
    });

    const handleInput = (e) =>
    {
        e.persist();
        setLoginInput({ ...loginInput, [e.target.name]: e.target.value });
    };

    const loginSubmit = (e) =>
    {
        e.preventDefault();

        const data = {
            email: loginInput.email,
            password: loginInput.password,
        };

        axios.post('/api/login', data).then(res =>
        {
            if (res.data.status === 200)
            {
                /**
                 * This is the key change.
                 * We now store the token AND the full user object from the API response.
                 * The user object contains the 'role_as' property.
                 */
                localStorage.setItem('auth_token', res.data.token);
                localStorage.setItem('auth_user', JSON.stringify(res.data.user));

                Swal.fire
                ({
                    title: "Success",
                    text: res.data.message,
                    icon: "success",
                    timer: 2000,
                    showConfirmButton: false
                });

                // Check the user's role and navigate to the correct page.
                if (res.data.user.role_as === 1) // 1 == Admin
                {
                    navigate('/admin/dashboard');
                }
                else // 0 == Regular User
                {
                    navigate('/home');
                }
            }
            else if (res.data.status === 401)
            {
                Swal.fire({
                    title: "Login Failed",
                    text: res.data.message,
                    icon: "warning"
                });
            }
            else
            {
                // Handle validation errors (e.g., email or password format is wrong)
                setLoginInput({ ...loginInput, error_list: res.data.validation_errors || {} });
            }
        }).catch(error =>
        {
            // The global interceptor in App.js will handle most 401s,
            // but we can show a generic error for other server issues.
            if (error.response && error.response.status !== 401)
            {
                Swal.fire({
                    title: "Forbidden!",
                    text: "Access Denied. You are not an Admin.",
                    icon: "Error",
                });
            }
        });
    };

    return (
        <div>
            <Navbar />
            <div className="container py-5">
                <div className="row justify-content-center">
                    <div className="col-md-6">
                        <div className="card">
                            <div className="card-header"><h4>Login</h4></div>
                            <div className="card-body">
                                <form onSubmit={loginSubmit}>
                                    <div className="form-group mb-3">
                                        <label>Email ID</label>
                                        <input type="email" name="email" onChange={handleInput} value={loginInput.email} className="form-control" />
                                        <span className="text-danger">{loginInput.error_list.email}</span>
                                    </div>
                                    <div className="form-group mb-3">
                                        <label>Password</label>
                                        <input type="password" name="password" onChange={handleInput} value={loginInput.password} className="form-control" />
                                        <span className="text-danger">{loginInput.error_list.password}</span>
                                    </div>
                                    <button type="submit" className="btn btn-primary">Login</button>
                                </form>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default Login;
